164: void ActiveStreamFilterBase::commonHandleBufferData(Buffer::Instance& provided_data) {
165: 
166:   // The way we do buffering is a little complicated which is why we have this common function
167:   // which is used for both encoding and decoding. When data first comes into our filter pipeline,
168:   // we send it through. Any filter can choose to stop iteration and buffer or not. If we then
169:   // continue iteration in the future, we use the buffered data. A future filter can stop and
170:   // buffer again. In this case, since we are already operating on buffered data, we don't
171:   // rebuffer, because we assume the filter has modified the buffer as it wishes in place.
172:   if (bufferedData().get() != &provided_data) {
173:     if (!bufferedData()) {
174:       bufferedData() = createBuffer();
175:     }
176:     bufferedData()->move(provided_data);
177:   }
178: }
