130: // Express percentage as [0, TimeoutPrecisionFactor] because stats do not accept floating point
131: // values, and getting multiple significant figures on the histogram would be nice.
132: uint64_t FilterUtility::percentageOfTimeout(const std::chrono::milliseconds response_time,
133:                                             const std::chrono::milliseconds timeout) {
134:   // Timeouts of 0 are considered infinite. Any portion of an infinite timeout used is still
135:   // none of it.
136:   if (timeout.count() == 0) {
137:     return 0;
138:   }
139: 
140:   return static_cast<uint64_t>(response_time.count() * TimeoutPrecisionFactor / timeout.count());
141: }
