308: void ConnectionManagerImpl::doDeferredStreamDestroy(ActiveStream& stream) {
309:   if (!stream.state_.is_internally_destroyed_) {
310:     ++closed_non_internally_destroyed_requests_;
311:     if (isPrematureRstStream(stream)) {
312:       ++number_premature_stream_resets_;
313:     }
314:   }
315:   if (stream.max_stream_duration_timer_ != nullptr) {
316:     stream.max_stream_duration_timer_->disableTimer();
317:     stream.max_stream_duration_timer_ = nullptr;
318:   }
319:   if (stream.stream_idle_timer_ != nullptr) {
320:     stream.stream_idle_timer_->disableTimer();
321:     stream.stream_idle_timer_ = nullptr;
322:   }
323:   stream.filter_manager_.disarmRequestTimeout();
324:   if (stream.request_header_timer_ != nullptr) {
325:     stream.request_header_timer_->disableTimer();
326:     stream.request_header_timer_ = nullptr;
327:   }
328:   if (stream.access_log_flush_timer_ != nullptr) {
329:     stream.access_log_flush_timer_->disableTimer();
330:     stream.access_log_flush_timer_ = nullptr;
331:   }
332: 
333:   // Only destroy the active stream if the underlying codec has notified us of
334:   // completion or we've internal redirect the stream.
335:   if (!stream.canDestroyStream()) {
336:     // Track that this stream is not expecting any additional calls apart from
337:     // codec notification.
338:     stream.state_.is_zombie_stream_ = true;
339:     return;
340:   }
341: 
342:   if (stream.response_encoder_ != nullptr) {
343:     stream.response_encoder_->getStream().registerCodecEventCallbacks(nullptr);
344:   }
345: 
346:   stream.completeRequest();
347:   stream.filter_manager_.onStreamComplete();
348: 
349:   // For HTTP/3, skip access logging here and add deferred logging info
350:   // to stream info for QuicStatsGatherer to use later.
351:   if (codec_ && codec_->protocol() == Protocol::Http3 &&
352:       // There was a downstream reset, log immediately.
353:       !stream.filter_manager_.sawDownstreamReset() &&
354:       // On recreate stream, log immediately.
355:       stream.response_encoder_ != nullptr &&
356:       Runtime::runtimeFeatureEnabled(
357:           "envoy.reloadable_features.quic_defer_logging_to_ack_listener")) {
358:     stream.deferHeadersAndTrailers();
359:   } else {
360:     // For HTTP/1 and HTTP/2, log here as usual.
361:     stream.log(AccessLog::AccessLogType::DownstreamEnd);
362:   }
363: 
364:   stream.filter_manager_.destroyFilters();
365: 
366:   dispatcher_->deferredDelete(stream.removeFromList(streams_));
367: 
368:   // The response_encoder should never be dangling (unless we're destroying a
369:   // stream we are recreating) as the codec level stream will either outlive the
370:   // ActiveStream, or be alive in deferred deletion queue at this point.
371:   if (stream.response_encoder_) {
372:     stream.response_encoder_->getStream().removeCallbacks(stream);
373:   }
374: 
375:   if (connection_idle_timer_ && streams_.empty()) {
376:     connection_idle_timer_->enableTimer(config_->idleTimeout().value());
377:   }
378:   maybeDrainDueToPrematureResets();
379: }
