54: void ActiveTcpSocket::startTimer() {
55:   if (listener_.listener_filters_timeout_.count() > 0) {
56:     timer_ = listener_.dispatcher().createTimer([this]() -> void { onTimeout(); });
57:     timer_->enableTimer(listener_.listener_filters_timeout_);
58:   }
59: }
